// Reproduction script to verify maskSensitiveData with custom patterns
const { maskSensitiveData, createPattern } = require('invisi-data');

// Test 1: Basic maskSensitiveData works
const testString1 = 'I send post request "/login", {"username":"user@test.com","password":"123456"}';
const result1 = maskSensitiveData(testString1);
console.log('Test 1 - Default masking:');
console.log('  Input: ', testString1);
console.log('  Output:', result1);
console.log('  Password masked:', result1.includes('****'));
console.log();

// Test 2: maskSensitiveData with custom patterns (email masking)
const emailPattern = createPattern(
  'Email',
  /"username"\s*:\s*"([^"\s]+@[^"\s]+)"/gi,
  '"username": "****"'
);

const result2 = maskSensitiveData(testString1, [emailPattern]);
console.log('Test 2 - Custom email pattern:');
console.log('  Input: ', testString1);
console.log('  Output:', result2);
console.log('  Email masked:', !result2.includes('user@test.com'));
console.log('  Password still masked:', result2.includes('****'));
console.log();

// Test 3: Verify that output.js currently does NOT pass custom patterns
// This simulates what output.js does
global.maskSensitiveData = true;
const isMaskedData = () => global.maskSensitiveData === true || false;
const result3 = isMaskedData() ? maskSensitiveData(testString1) : testString1;
console.log('Test 3 - Simulating current output.js behavior:');
console.log('  Output:', result3);
console.log('  Email is NOT masked (current limitation):', result3.includes('user@test.com'));
console.log();

console.log('=== Summary ===');
console.log('maskSensitiveData supports custom patterns:', typeof maskSensitiveData === 'function');
console.log('createPattern is available:', typeof createPattern === 'function');
console.log('Current output.js does NOT pass custom patterns to maskSensitiveData');
console.log('Need to: allow config.maskSensitiveData to accept { customPatterns: [...] }');

