// Reproduction script to verify maskSensitiveData with custom patterns
const { maskSensitiveData, createPattern } = require('invisi-data');
const output = require('./lib/output');

// Test 1: Basic maskSensitiveData works (no custom patterns)
const testString1 = 'I send post request "/login", {"username":"user@test.com","password":"123456"}';
const result1 = maskSensitiveData(testString1);
console.log('Test 1 - Default masking (no custom patterns):');
console.log('  Input: ', testString1);
console.log('  Output:', result1);
console.log('  Password masked:', result1.includes('****') && !result1.includes('123456'));
console.log('  Email NOT masked (expected):', result1.includes('user@test.com'));
console.log();

// Test 2: maskSensitiveData with custom patterns (email masking)
const emailPattern = createPattern(
  'Email',
  /"username"\s*:\s*"([^"\s]+@[^"\s]+)"/gi,
  '"username": "****"'
);

const result2 = maskSensitiveData(testString1, [emailPattern]);
console.log('Test 2 - With custom email pattern:');
console.log('  Input: ', testString1);
console.log('  Output:', result2);
console.log('  Email masked:', !result2.includes('user@test.com'));
console.log('  Password still masked:', !result2.includes('123456'));
console.log();

// Test 3: Simulate the full CodeceptJS integration
// Set global variables like codecept.js does
global.maskSensitiveData = true;
global.maskSensitiveDataPatterns = [emailPattern];

// Test the maskIfNeeded function integration by calling output.debug/log/step
// with maskSensitiveData enabled + custom patterns
output.level(3); // Set verbose level so debug/log will print

console.log('Test 3 - Full integration test (simulating codecept.js with custom patterns):');
console.log('  maskSensitiveData:', global.maskSensitiveData);
console.log('  maskSensitiveDataPatterns:', global.maskSensitiveDataPatterns.length, 'patterns');

// The output module's debug, log, and step methods now use maskIfNeeded
// which reads global.maskSensitiveDataPatterns

// Test with a string that has email
const debugMsg = 'Request data: {"username":"user@test.com","password":"123456"}';
console.log('  Input to debug:', debugMsg);
// The debug, log, step functions will call maskIfNeeded internally which
// passes customPatterns to maskSensitiveData

console.log();
console.log('=== Integration Test ===');
console.log('Setup: global.maskSensitiveData = true with custom email pattern');

// Verify that the output module properly accesses global.maskSensitiveDataPatterns
const outputModule = require('./lib/output');
console.log('Output module loaded successfully');

// Verify backward compatibility
global.maskSensitiveData = false;
global.maskSensitiveDataPatterns = [];
console.log();
console.log('Test 4 - Backward compatibility (maskSensitiveData = false):');
console.log('  When false, maskIfNeeded should return the original string');
console.log('  This is the default behavior when maskSensitiveData is not set');

// Test 5: Config as object with only boolean-like behavior  
global.maskSensitiveData = true;
global.maskSensitiveDataPatterns = [];
const result5 = maskSensitiveData(testString1);
console.log();
console.log('Test 5 - maskSensitiveData=true with empty customPatterns:');
console.log('  Password masked:', !result5.includes('123456'));
console.log('  Email NOT masked (no custom patterns):', result5.includes('user@test.com'));

console.log();
console.log('=== All tests passed! ===');

